                        <button onClick={()=>store.updateLeaveRequest(req.id,{status:"rejected"})} style={{padding:"5px 12px",borderRadius:7,border:"none",background:C.red+"22",color:C.red,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Inter',sans-serif"}}>Reject</button>
