              <button onClick={()=>store.removeNotice(n.id)} style={{marginLeft:16,padding:"6px 12px",borderRadius:8,border:`1px solid ${C.red}44`,background:"none",color:C.red,cursor:"pointer",fontSize:12,fontFamily:"'Inter',sans-serif",flexShrink:0}}>Delete</button>
